/** Paths for sitemap and prerender: /seo/:locationSlug/:serviceSlug */
export function getSeoLocationPaths(): string[] {
    return SEO_LOCATION_PAGES.map((e) => `/seo/${e.locationSlug}/${e.serviceSlug}`);
}

export function findSeoLocationPage(locationSlug: string, serviceSlug: string): SeoLocationPageEntry | undefined {
    return SEO_LOCATION_PAGES.find((e) => e.locationSlug === locationSlug && e.serviceSlug === serviceSlug);
}

/** Kerala (India) district slugs — for /kerala hub. When users search "Kerala" they see this page. */
const KERALA_LOCATION_SLUGS = new Set([
    'thrissur', 'ernakulam', 'kozhikode', 'kollam', 'thiruvananthapuram', 'palakkad', 'kannur',
    'malappuram', 'kottayam', 'alappuzha', 'pathanamthitta', 'idukki', 'wayanad', 'kasaragod',
]);

/** Gulf (UAE + Saudi etc.) location slugs — for /gulf-vat hub. When users search "Gulf VAT" they see that page. */
const GULF_LOCATION_SLUGS = new Set([
    'uae', 'dubai', 'abu-dhabi', 'sharjah', 'ajman', 'ras-al-khaimah', 'fujairah', 'umm-al-quwain',
    'riyadh', 'jeddah',
]);

const UNITED_STATES_LOCATION_SLUGS = new Set(['united-states']);

/** All Kerala SEO pages (one per district×service). For /kerala hub. */
export function getKeralaSeoPages(): SeoLocationPageEntry[] {
    return SEO_LOCATION_PAGES.filter((e) => KERALA_LOCATION_SLUGS.has(e.locationSlug));
}

/** Unique Kerala districts with at least one page (for hub links). */
export function getKeralaDistricts(): SeoLocationPageEntry[] {
    const seen = new Set<string>();
    return SEO_LOCATION_PAGES.filter((e) => {
        if (!KERALA_LOCATION_SLUGS.has(e.locationSlug)) return false;
        if (seen.has(e.locationSlug)) return false;
        seen.add(e.locationSlug);
        return true;
    });
}

/** Gulf VAT billing SEO pages. When users search "Gulf VAT" show /gulf-vat with links to these. */
export function getGulfVatPages(): SeoLocationPageEntry[] {
    return SEO_LOCATION_PAGES.filter(
        (e) => GULF_LOCATION_SLUGS.has(e.locationSlug) && e.serviceSlug === 'vat-billing'
    );
}

/** United States SEO pages for the /united-states hub. */
export function getUnitedStatesSeoPages(): SeoLocationPageEntry[] {
    return SEO_LOCATION_PAGES.filter((e) => UNITED_STATES_LOCATION_SLUGS.has(e.locationSlug));
}
